import{_ as r,o as a,c as i,aA as t,j as d}from"./chunks/framework.DOg9rr25.js";const y=JSON.parse('{"title":"Pulseq Event Mapping","description":"","frontmatter":{},"headers":[],"relativePath":"explanation/6-pulseq-event-mapping.md","filePath":"explanation/6-pulseq-event-mapping.md","lastUpdated":null}'),o={name:"explanation/6-pulseq-event-mapping.md"},s={style:{"overflow-x":"auto",margin:"1rem 0"}},l={viewBox:"0 0 900 220",role:"img","aria-label":"Pulseq reader pipeline",style:{"min-width":"720px",width:"100%",height:"auto"}},n={style:{"overflow-x":"auto",margin:"1rem 0"}},c={viewBox:"0 0 900 220",role:"img","aria-label":"Pulseq writer pipeline",style:{"min-width":"720px",width:"100%",height:"auto"}};function h(m,e,p,f,g,x){return a(),i("div",null,[e[2]||(e[2]=t('<h1 id="Pulseq-Event-Mapping" tabindex="-1">Pulseq Event Mapping <a class="header-anchor" href="#Pulseq-Event-Mapping" aria-label="Permalink to &quot;Pulseq Event Mapping {#Pulseq-Event-Mapping}&quot;">​</a></h1><p>KomaMRI uses two representations:</p><ul><li><p><a href="./4-sequence"><code>Sequence</code></a>: the runtime representation used by simulation and plotting. It stores repeated block events as <a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#rf"><code>RF</code></a>, <a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#gradient"><code>Grad</code></a>, and <a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#adc"><code>ADC</code></a> objects. See <a href="./4-sequence">Sequence</a> for the sequence model.</p></li><li><p><a href="/KomaMRI.jl/previews/PR756/reference/4-koma-files#KomaMRIFiles.PulseqSequenceData"><code>PulseqSequenceData</code></a>: the Pulseq-native intermediate representation used by the reader and writer. It stores <code>[BLOCKS]</code> rows, event libraries, definitions, the Pulseq version, and the optional signature.</p></li></ul><p>API references: <a href="/KomaMRI.jl/previews/PR756/reference/4-koma-files#KomaMRIFiles.read_seq"><code>read_seq</code></a>, <a href="/KomaMRI.jl/previews/PR756/reference/4-koma-files#KomaMRIFiles.read_seq_data"><code>read_seq_data</code></a>, <a href="/KomaMRI.jl/previews/PR756/reference/4-koma-files#KomaMRIFiles.write_seq"><code>write_seq</code></a>, <a href="/KomaMRI.jl/previews/PR756/reference/4-koma-files#KomaMRIFiles.write_seq_data"><code>write_seq_data</code></a>, and <a href="/KomaMRI.jl/previews/PR756/reference/4-koma-files#KomaMRIFiles.PulseqSequenceData"><code>PulseqSequenceData</code></a>.</p><h2 id="Reader" tabindex="-1">Reader <a class="header-anchor" href="#Reader" aria-label="Permalink to &quot;Reader {#Reader}&quot;">​</a></h2><p><a href="/KomaMRI.jl/previews/PR756/reference/4-koma-files#KomaMRIFiles.read_seq"><code>read_seq</code></a> first reads the file into <a href="/KomaMRI.jl/previews/PR756/reference/4-koma-files#KomaMRIFiles.PulseqSequenceData"><code>PulseqSequenceData</code></a>, then materializes a Koma <code>Sequence</code>. Use <a href="/KomaMRI.jl/previews/PR756/reference/4-koma-files#KomaMRIFiles.read_seq_data"><code>read_seq_data</code></a> when you want the Pulseq block/event-library representation without expanding every block into Koma events.</p>',6)),d("div",s,[(a(),i("svg",l,[...e[0]||(e[0]=[t('<defs><marker id="reader-arrow" markerWidth="10" markerHeight="10" refX="9" refY="3" orient="auto"><path d="M0,0 L0,6 L9,3 z" fill="#64748b"></path></marker></defs><rect x="35" y="60" width="135" height="70" rx="12" fill="#eef6ff" stroke="#60a5fa" stroke-width="2"></rect><text x="102" y="90" text-anchor="middle" font-size="16" font-weight="700">.seq file</text><text x="102" y="112" text-anchor="middle" font-size="12">Pulseq sections</text><line x1="170" y1="95" x2="225" y2="95" stroke="#64748b" stroke-width="2" marker-end="url(#reader-arrow)"></line><rect x="235" y="48" width="205" height="94" rx="12" fill="#f8fafc" stroke="#94a3b8" stroke-width="2"></rect><text x="337" y="78" text-anchor="middle" font-size="16" font-weight="700">read_seq_data</text><text x="337" y="101" text-anchor="middle" font-size="12">parse sections + scales</text><text x="337" y="120" text-anchor="middle" font-size="12">legacy fixups + optional signature</text><line x1="440" y1="95" x2="495" y2="95" stroke="#64748b" stroke-width="2" marker-end="url(#reader-arrow)"></line><rect x="505" y="60" width="180" height="70" rx="12" fill="#fff7ed" stroke="#fb923c" stroke-width="2"></rect><text x="595" y="90" text-anchor="middle" font-size="16" font-weight="700">PulseqSequenceData</text><text x="595" y="112" text-anchor="middle" font-size="12">ids + event libraries</text><line x1="685" y1="95" x2="740" y2="95" stroke="#64748b" stroke-width="2" marker-end="url(#reader-arrow)"></line><rect x="750" y="48" width="115" height="94" rx="12" fill="#ecfdf5" stroke="#34d399" stroke-width="2"></rect><text x="807" y="79" text-anchor="middle" font-size="16" font-weight="700">Sequence</text><text x="807" y="101" text-anchor="middle" font-size="12">decode once</text><text x="807" y="120" text-anchor="middle" font-size="12">expand blocks</text><text x="450" y="185" text-anchor="middle" font-size="13" fill="#64748b">read_seq_data stops at the Pulseq-native representation; read_seq continues through Sequence(data).</text>',19)])]))]),e[3]||(e[3]=t('<p>The reader has three stages:</p><ol><li><p><code>parse_pulseq_file</code> reads sections into <code>PulseqParsedFile</code>. It applies version-specific scales, for example <code>γ</code> conversion for RF/gradient amplitudes and <code>μs</code>/<code>ns</code> conversion for timing fields.</p></li><li><p><code>pulseq_sequence_data</code> normalizes legacy details and returns <a href="/KomaMRI.jl/previews/PR756/reference/4-koma-files#KomaMRIFiles.PulseqSequenceData"><code>PulseqSequenceData</code></a>. This is still Pulseq-native: blocks contain integer event ids, and event payloads live in libraries.</p></li><li><p><code>Sequence(data)</code> decodes each library entry once, then expands block ids into a Koma <code>Sequence</code>.</p></li></ol><h3 id="RF" tabindex="-1">RF <a class="header-anchor" href="#RF" aria-label="Permalink to &quot;RF {#RF}&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Pulseq RF timing</th><th style="text-align:right;">Koma fields</th><th style="text-align:right;">Koma representation</th></tr></thead><tbody><tr><td style="text-align:right;">no RF event id</td><td style="text-align:right;"><code>RF(0.0, 0.0)</code></td><td style="text-align:right;"><a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#rf"><code>BlockPulseRF</code></a></td></tr><tr><td style="text-align:right;"><code>time_shape_id == 0</code></td><td style="text-align:right;"><code>A::Vector</code>, <code>T::Number</code>; <code>delay = pulseq_delay + Δt_rf/2</code></td><td style="text-align:right;"><a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#rf-uniformly-sampled-waveform"><code>UniformlySampledRF</code></a></td></tr><tr><td style="text-align:right;"><code>time_shape_id == -1</code></td><td style="text-align:right;"><code>A::Vector</code>, <code>T::Number</code>; half-raster compact timing; <code>delay = pulseq_delay + Δt_rf/2</code></td><td style="text-align:right;"><a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#rf-uniformly-sampled-waveform"><code>UniformlySampledRF</code></a></td></tr><tr><td style="text-align:right;"><code>time_shape_id &gt; 0</code></td><td style="text-align:right;"><code>A::Vector</code>, <code>T::Vector = diff(time_shape) * Δt_rf</code>; <code>delay = pulseq_delay + first(time_shape) * Δt_rf</code></td><td style="text-align:right;"><a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#rf-time-shaped-waveform"><code>TimeShapedRF</code></a></td></tr></tbody></table><p>Pulseq RF events store magnitude and phase as shapes. Therefore, even a constant RF pulse in a Pulseq file is read as a sampled RF waveform, not as a scalar <code>BlockPulseRF</code>. <code>BlockPulseRF</code> appears for empty RF placeholders and Koma-native scalar RF construction.</p><p>Compact RF timing uses Pulseq&#39;s center-sampled convention: Pulseq stores <code>pulseq_delay</code> before the implicit first-sample offset, while Koma stores <code>delay</code> to the first RF sample. For compact RF timing, these differ by <code>Δt_rf/2</code>.</p><h3 id="Gradients" tabindex="-1">Gradients <a class="header-anchor" href="#Gradients" aria-label="Permalink to &quot;Gradients {#Gradients}&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Pulseq gradient form</th><th style="text-align:right;">Koma fields</th><th style="text-align:right;">Koma representation</th></tr></thead><tbody><tr><td style="text-align:right;">no gradient event id</td><td style="text-align:right;"><code>Grad(0.0, 0.0)</code></td><td style="text-align:right;"><a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#gradient-trapezoidal-waveform"><code>TrapezoidalGrad</code></a></td></tr><tr><td style="text-align:right;"><code>[TRAP]</code> event</td><td style="text-align:right;"><code>A::Number</code>, <code>T::Number</code>, scalar rise/fall</td><td style="text-align:right;"><a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#gradient-trapezoidal-waveform"><code>TrapezoidalGrad</code></a></td></tr><tr><td style="text-align:right;"><code>[GRADIENTS]</code>, <code>time_shape_id == 0</code></td><td style="text-align:right;"><code>A::Vector</code>, <code>T::Number</code>, <code>rise = fall = Δt_gr/2</code></td><td style="text-align:right;"><a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#gradient-uniformly-sampled-waveform"><code>UniformlySampledGrad</code></a></td></tr><tr><td style="text-align:right;"><code>[GRADIENTS]</code>, <code>time_shape_id == -1</code></td><td style="text-align:right;"><code>A::Vector</code>, <code>T::Number</code>, half-raster compact timing, <code>rise = fall = Δt_gr/2</code></td><td style="text-align:right;"><a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#gradient-uniformly-sampled-waveform"><code>UniformlySampledGrad</code></a></td></tr><tr><td style="text-align:right;"><code>[GRADIENTS]</code>, <code>time_shape_id &gt; 0</code></td><td style="text-align:right;"><code>A::Vector</code>, <code>T::Vector = diff(time_shape) * Δt_gr</code>; <code>delay += first(time_shape) * Δt_gr</code>; <code>rise = fall = 0</code></td><td style="text-align:right;"><a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#gradient-time-shaped-waveform"><code>TimeShapedGrad</code></a></td></tr></tbody></table><p>For Pulseq versions before 1.5, the reader also reconstructs missing arbitrary gradient <code>first</code>/<code>last</code> values from neighboring blocks before materializing the Koma sequence.</p><h3 id="ADC" tabindex="-1">ADC <a class="header-anchor" href="#ADC" aria-label="Permalink to &quot;ADC {#ADC}&quot;">​</a></h3><p><a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#adc"><code>ADC</code></a> events do not have shape-based representations. The timing convention is the only translation: Koma stores <code>delay</code> to the first acquired sample, while Pulseq stores <code>pulseq_delay</code> to the dwell interval edge.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Pulseq ADC timing</th><th style="text-align:right;">Koma fields</th></tr></thead><tbody><tr><td style="text-align:right;">no ADC event id</td><td style="text-align:right;"><code>ADC(0, 0.0)</code></td></tr><tr><td style="text-align:right;"><code>[ADC]</code> event</td><td style="text-align:right;"><code>N = num</code>, <code>T = dwell * (num - 1)</code>, <code>delay = pulseq_delay + dwell/2</code></td></tr></tbody></table><p>On read, <code>T</code> is the time from the first sample to the last sample. A single sample therefore reads as <code>T = 0</code>.</p><h2 id="Writer" tabindex="-1">Writer <a class="header-anchor" href="#Writer" aria-label="Permalink to &quot;Writer {#Writer}&quot;">​</a></h2><p><a href="/KomaMRI.jl/previews/PR756/reference/4-koma-files#KomaMRIFiles.write_seq"><code>write_seq</code></a> converts a Koma <code>Sequence</code> into <a href="/KomaMRI.jl/previews/PR756/reference/4-koma-files#KomaMRIFiles.PulseqSequenceData"><code>PulseqSequenceData</code></a> and then emits Pulseq sections. Use <a href="/KomaMRI.jl/previews/PR756/reference/4-koma-files#KomaMRIFiles.write_seq_data"><code>write_seq_data</code></a> to get that Pulseq-native representation without writing a file. <code>write_seq(data::PulseqSequenceData, filename)</code> writes an already prepared representation directly.</p>',15)),d("div",n,[(a(),i("svg",c,[...e[1]||(e[1]=[t('<defs><marker id="writer-arrow" markerWidth="10" markerHeight="10" refX="9" refY="3" orient="auto"><path d="M0,0 L0,6 L9,3 z" fill="#64748b"></path></marker></defs><rect x="35" y="60" width="135" height="70" rx="12" fill="#ecfdf5" stroke="#34d399" stroke-width="2"></rect><text x="102" y="90" text-anchor="middle" font-size="16" font-weight="700">Sequence</text><text x="102" y="112" text-anchor="middle" font-size="12">runtime events</text><line x1="170" y1="95" x2="225" y2="95" stroke="#64748b" stroke-width="2" marker-end="url(#writer-arrow)"></line><rect x="235" y="42" width="210" height="106" rx="12" fill="#f8fafc" stroke="#94a3b8" stroke-width="2"></rect><text x="340" y="70" text-anchor="middle" font-size="16" font-weight="700">write_seq_data</text><text x="340" y="94" text-anchor="middle" font-size="12">hardware checks</text><text x="340" y="113" text-anchor="middle" font-size="12">raster + quantize</text><text x="340" y="132" text-anchor="middle" font-size="12">timing check + deduplicate</text><line x1="445" y1="95" x2="500" y2="95" stroke="#64748b" stroke-width="2" marker-end="url(#writer-arrow)"></line><rect x="510" y="60" width="180" height="70" rx="12" fill="#fff7ed" stroke="#fb923c" stroke-width="2"></rect><text x="600" y="90" text-anchor="middle" font-size="16" font-weight="700">PulseqSequenceData</text><text x="600" y="112" text-anchor="middle" font-size="12">ids + event libraries</text><line x1="690" y1="95" x2="745" y2="95" stroke="#64748b" stroke-width="2" marker-end="url(#writer-arrow)"></line><rect x="755" y="60" width="110" height="70" rx="12" fill="#eef6ff" stroke="#60a5fa" stroke-width="2"></rect><text x="810" y="90" text-anchor="middle" font-size="16" font-weight="700">.seq file</text><text x="810" y="112" text-anchor="middle" font-size="12">sections + signature</text><text x="450" y="185" text-anchor="middle" font-size="13" fill="#64748b">write_seq(seq; sys) uses sys for checks and rasters; write_seq(data, filename) skips Koma rasterization.</text>',19)])]))]),e[4]||(e[4]=t('<p>The writer has four stages:</p><ol><li><p>By default, <code>check_hw_limits=true</code> checks hardware limits before writing. Without <code>sys</code>, this uses metadata in <code>seq.DEF</code>; with <code>sys</code>, it uses <code>sys</code>.</p></li><li><p><code>prepare_pulseq_write</code> copies and quantizes RF, gradient, ADC, and block duration timings to the Pulseq rasters. Without <code>sys</code>, raster times come from <code>seq.DEF</code>; with <code>sys</code>, the scanner rasters are used.</p></li><li><p>By default, <code>check_timing=true</code> checks the quantized copy against the Pulseq rasters.</p></li><li><p><code>collect_pulseq_assets</code> and <code>emit_pulseq</code> write <code>[DEFINITIONS]</code>, <code>[BLOCKS]</code>, event libraries, shape libraries, extensions, and the signature.</p></li></ol><p>Hardware-limit definitions such as <code>MaxGrad</code>, <code>MaxSlew</code>, <code>MaxB1</code>, and dead times are Koma check metadata. They are not emitted to the Pulseq <code>[DEFINITIONS]</code> section; the writer emits Pulseq raster definitions and non-internal user definitions.</p><h3 id="RF-2" tabindex="-1">RF <a class="header-anchor" href="#RF-2" aria-label="Permalink to &quot;RF {#RF-2}&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Koma RF condition</th><th style="text-align:right;">Pulseq output</th></tr></thead><tbody><tr><td style="text-align:right;"><code>!is_on(rf)</code></td><td style="text-align:right;">no RF event id</td></tr><tr><td style="text-align:right;"><a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#rf"><code>BlockPulseRF</code></a></td><td style="text-align:right;"><code>[RF]</code> event with constant magnitude and phase shapes</td></tr><tr><td style="text-align:right;"><a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#rf-uniformly-sampled-waveform"><code>UniformlySampledRF</code></a> with sample times <code>0, Δt_rf, 2Δt_rf, ...</code> and compatible delay</td><td style="text-align:right;"><code>[RF]</code> with <code>time_shape_id = 0</code>; <code>pulseq_delay = rf.delay - Δt_rf/2</code></td></tr><tr><td style="text-align:right;"><a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#rf-uniformly-sampled-waveform"><code>UniformlySampledRF</code></a> with half-raster sample times and odd sample count</td><td style="text-align:right;"><code>[RF]</code> with <code>time_shape_id = -1</code>; <code>pulseq_delay = rf.delay - Δt_rf/2</code></td></tr><tr><td style="text-align:right;"><a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#rf-time-shaped-waveform"><code>TimeShapedRF</code></a></td><td style="text-align:right;"><code>[RF]</code> with an explicit time shape</td></tr><tr><td style="text-align:right;">otherwise</td><td style="text-align:right;"><code>[RF]</code> with an explicit time shape</td></tr></tbody></table><p><code>TimeShapedRF</code> is always written with an explicit time shape. This preserves vector timing and avoids replacing it with Pulseq&#39;s compact RF convention, where the first RF sample is implicitly offset by <code>Δt_rf/2</code>.</p><p>Frequency-modulated RF waveforms are not written to Pulseq: <code>FrequencyModulatedRF</code> throws an error in the writer.</p><h3 id="Gradients-2" tabindex="-1">Gradients <a class="header-anchor" href="#Gradients-2" aria-label="Permalink to &quot;Gradients {#Gradients-2}&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Koma gradient condition</th><th style="text-align:right;">Pulseq output</th></tr></thead><tbody><tr><td style="text-align:right;"><code>!is_on(gr)</code> and zero duration</td><td style="text-align:right;">no gradient event id</td></tr><tr><td style="text-align:right;"><a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#gradient-trapezoidal-waveform"><code>TrapezoidalGrad</code></a> with <code>first == last == 0</code></td><td style="text-align:right;"><code>[TRAP]</code></td></tr><tr><td style="text-align:right;"><a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#gradient-trapezoidal-waveform"><code>TrapezoidalGrad</code></a> with nonzero edge continuity</td><td style="text-align:right;">converted to an edge-timed arbitrary gradient, then <code>[GRADIENTS]</code></td></tr><tr><td style="text-align:right;"><a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#gradient-uniformly-sampled-waveform"><code>UniformlySampledGrad</code></a> with two equal samples and <code>first == last == 0</code></td><td style="text-align:right;"><code>[TRAP]</code></td></tr><tr><td style="text-align:right;"><a href="/KomaMRI.jl/previews/PR756/explanation/5-seq-events#gradient-time-shaped-waveform"><code>TimeShapedGrad</code></a> with two equal samples, one interval, and <code>first == last == 0</code></td><td style="text-align:right;"><code>[TRAP]</code></td></tr><tr><td style="text-align:right;">arbitrary gradient sample times match <code>(i - 1/2)Δt_gr</code></td><td style="text-align:right;"><code>[GRADIENTS]</code> with <code>time_shape_id = 0</code></td></tr><tr><td style="text-align:right;">arbitrary gradient sample times match <code>i * Δt_gr/2</code> with odd sample count</td><td style="text-align:right;"><code>[GRADIENTS]</code> with <code>time_shape_id = -1</code></td></tr><tr><td style="text-align:right;">otherwise</td><td style="text-align:right;"><code>[GRADIENTS]</code> with an explicit time shape</td></tr></tbody></table><p>Unlike RF, a <code>TimeShapedGrad</code> may still be compacted if its sample times exactly match a Pulseq compact gradient timing convention. Gradient compact timing does not carry the same RF first-sample convention, so this is a representation optimization.</p><h3 id="ADC-2" tabindex="-1">ADC <a class="header-anchor" href="#ADC-2" aria-label="Permalink to &quot;ADC {#ADC-2}&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Koma ADC condition</th><th style="text-align:right;">Pulseq output</th></tr></thead><tbody><tr><td style="text-align:right;"><code>!is_on(adc)</code></td><td style="text-align:right;">no ADC event id</td></tr><tr><td style="text-align:right;"><code>N == 1</code></td><td style="text-align:right;"><code>[ADC]</code> with <code>dwell = T</code>, <code>pulseq_delay = delay - dwell/2</code></td></tr><tr><td style="text-align:right;"><code>N &gt; 1</code></td><td style="text-align:right;"><code>[ADC]</code> with <code>dwell = T / (N - 1)</code>, <code>pulseq_delay = delay - dwell/2</code></td></tr></tbody></table><p>Pulseq ADC timing follows an edge-versus-sample convention: the Pulseq delay points to the dwell interval edge, and the first sample is acquired at <code>dwell/2</code>. Koma stores <code>delay</code> at the first acquired sample, so the writer subtracts <code>dwell/2</code> and the reader adds it back.</p><p>For <code>N == 1</code>, the writer uses <code>T</code> as the dwell time because there is no inter-sample interval from which to infer it.</p>',14))])}const w=r(o,[["render",h]]);export{y as __pageData,w as default};
